const envelope = $input.first().json || {};
const payload = envelope.payload || {};

const trim = (value) => String(value || '').trim();
const candidateUrls = Array.isArray(payload.candidate_urls)
  ? payload.candidate_urls.map((value) => trim(value)).filter(Boolean)
  : [];
const siteBaseUrl = trim(payload.site_url || $env.SITE_URL || $env.SIMONE_WEB_BASE_URL || $env.NEXT_PUBLIC_SITE_URL || '').replace(/\/$/, '');
const callbackPath = trim(payload.callback_path || '/api/admin/suppliers/catalog-sync/callback');
const callbackUrl = trim(payload.callback_url || (siteBaseUrl ? `${siteBaseUrl}${callbackPath}` : ''));
const rawRunnerUrl = trim(
  payload.browser_runner_url ||
  $env.SUPPLIER_BROWSER_RUNNER_URL ||
  $env.BROWSER_RUNNER_WEBHOOK_URL ||
  (siteBaseUrl ? `${siteBaseUrl}/api/automation/supplier-catalog-browser/catalog-harvest` : '')
);
const runnerRequestUrl = rawRunnerUrl
  ? (rawRunnerUrl.endsWith('/catalog-harvest') ? rawRunnerUrl : `${rawRunnerUrl}/catalog-harvest`)
  : '';
const callbackSecret = trim(
  $env.SUPPLIER_CALLBACK_SECRET ||
  $env.SUPPLIER_ONBOARDING_CALLBACK_SECRET ||
  $env.SUPPLIER_WEBHOOK_SECRET ||
  $env.N8N_SHARED_SECRET ||
  ''
);
const internalToken = trim($env.SUPPLIER_BROWSER_RUNNER_TOKEN || callbackSecret);

return [{
  json: {
    eventType: trim(envelope.event_type),
    supplierId: trim(payload.supplier_id),
    supplierName: trim(payload.supplier_name),
    targetUrl: trim(payload.target_url || candidateUrls[0] || ''),
    candidateUrls,
    callbackPath,
    callbackUrl,
    callbackSecret,
    internalToken,
    browserRunnerUrl: rawRunnerUrl,
    runnerRequestUrl,
    catalogStatus: trim(payload.catalog_status || 'new') || 'new',
    browserRecipe: payload.browser_recipe || {},
    requestPayload: payload.request_payload || {},
    failureReason: trim(payload.failure_reason),
    failedSource: trim(payload.failed_source),
    runnerConfigured: Boolean(runnerRequestUrl && callbackUrl && callbackSecret && internalToken)
  }
}];

const request = $node['Browser-Auftrag normalisieren'].json || {};
const response = $input.first().json || {};
const crypto = require('crypto');

const trim = (value) => String(value || '').trim();
const rawItems = Array.isArray(response.items)
  ? response.items
  : Array.isArray(response.products)
    ? response.products
    : [];
const harvestedAt = new Date().toISOString();

const items = rawItems.map((item, index) => {
  const title = trim(item.title || item.name || item.product_name);
  if (!title) {
    return null;
  }

  return {
    external_product_id: trim(item.external_product_id || item.external_id || item.id || `${request.supplierId}-${index + 1}`),
    supplier_sku: trim(item.supplier_sku || item.sku),
    title,
    description: trim(item.description || item.body),
    source_url: trim(item.source_url || item.url || request.targetUrl),
    image_url: trim(item.image_url || item.image || item.thumbnail),
    currency: trim(item.currency || 'EUR').toUpperCase() || 'EUR',
    price: item.price ?? null,
    compare_at_price: item.compare_at_price ?? null,
    minimum_order_quantity: item.minimum_order_quantity ?? null,
    stock_hint: item.stock_hint ?? null,
    lead_time_days: item.lead_time_days ?? null,
    status: trim(item.status || request.catalogStatus || 'new') || 'new',
    review_note: trim(item.review_note),
    ai_score: item.ai_score ?? null,
    metadata: {
      ...(item.metadata || {}),
      harvest_target_url: request.targetUrl,
      harvested_at: harvestedAt,
      browser_source: 'n8n_browser_runner',
      browser_recipe: request.browserRecipe || {},
      runner_status: trim(response.status || 'completed') || 'completed'
    }
  };
}).filter(Boolean);

const callbackBody = {
  supplier_id: request.supplierId,
  items,
  source: 'browser_runner',
  synced_at: harvestedAt,
  metadata: {
    target_url: request.targetUrl,
    candidate_urls: request.candidateUrls,
    browser_recipe: request.browserRecipe || {},
    failed_source: request.failedSource,
    failure_reason: request.failureReason,
    runner_status: trim(response.status || 'completed') || 'completed'
  }
};

const serializedBody = JSON.stringify(callbackBody);
const signature = request.callbackSecret
  ? `sha256=${crypto.createHmac('sha256', request.callbackSecret).update(serializedBody).digest('hex')}`
  : '';

return [{
  json: {
    callbackUrl: request.callbackUrl,
    callbackBody,
    serializedBody,
    signature,
    itemsCount: items.length
  }
}];
